namespace test_reaction {

int test_reactive_update_chain(int a, int b, int newA) {
    auto node = std::make_shared<reaction::Node>();
    auto varA = reaction::VarExpr<int>(a, node);
    auto varB = reaction::VarExpr<int>(b, node);
    auto firstCalc = reaction::CalcExpr<int>([=]() { return varA->get() + varB->get(); }, node);
